<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\{Schedule,SchoolClass,Subject,Teacher};use Illuminate\Http\Request;
class ScheduleController extends Controller { public function index(){return view('admin.schedules.index',['items'=>Schedule::with(['teacher.user','schoolClass','subject'])->orderByRaw("FIELD(day_of_week,'Senin','Selasa','Rabu','Kamis','Jumat','Sabtu')")->orderBy('start_time')->paginate(20)]);} public function create(){return $this->form(new Schedule);} public function store(Request $r){Schedule::create($this->data($r));return redirect()->route('admin.schedules.index')->with('success','Jadwal ditambahkan.');} public function edit(Schedule $schedule){return $this->form($schedule);} public function update(Request $r,Schedule $schedule){$schedule->update($this->data($r));return redirect()->route('admin.schedules.index')->with('success','Jadwal diperbarui.');} public function destroy(Schedule $schedule){$schedule->delete();return back()->with('success','Jadwal dihapus.');} private function form(Schedule $item){return view('admin.schedules.form',compact('item')+['teachers'=>Teacher::with('user')->get(),'classes'=>SchoolClass::where('is_active',1)->get(),'subjects'=>Subject::where('is_active',1)->get()]);} private function data(Request $r){return $r->validate(['teacher_id'=>'required|exists:teachers,id','school_class_id'=>'required|exists:school_classes,id','subject_id'=>'required|exists:subjects,id','day_of_week'=>'required|in:Senin,Selasa,Rabu,Kamis,Jumat,Sabtu','start_time'=>'required','end_time'=>'required|after:start_time','room'=>'nullable|max:50','is_active'=>'nullable|boolean']);} }
